import{_ as i,c as l,o as a,a4 as t}from"./chunks/framework.nQaBHiNx.js";const O=JSON.parse('{"title":"输入输出管理","description":"","frontmatter":{"permalink":"/basic/computer/operating-system-intro/05.html"},"headers":[],"relativePath":"computer/book/operating-system-intro/05-第五章 输入输出管理.md","filePath":"computer/book/operating-system-intro/05-第五章 输入输出管理.md"}'),o={name:"computer/book/operating-system-intro/05-第五章 输入输出管理.md"},e=t('<h1 id="输入输出管理" tabindex="-1">输入输出管理 <a class="header-anchor" href="#输入输出管理" aria-label="Permalink to &quot;输入输出管理&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">知识结构</p><ul><li>I/O 管理概述 <ul><li>I/O 控制方式；I/O 软件层次结构</li></ul></li><li>I/O 核心子系统 <ul><li>I/O 调度概念；高速缓存与缓冲区</li><li>设备分配与回收；假脱机技术</li></ul></li></ul></div><h2 id="_5-1-i-o-管理概述" tabindex="-1">5.1 I/O 管理概述 <a class="header-anchor" href="#_5-1-i-o-管理概述" aria-label="Permalink to &quot;5.1 I/O 管理概述&quot;">​</a></h2><h3 id="_5-1-1-i-o-设备" tabindex="-1">5.1.1 I/O 设备 <a class="header-anchor" href="#_5-1-1-i-o-设备" aria-label="Permalink to &quot;5.1.1 I/O 设备&quot;">​</a></h3><p>IO 设备管理是操作系统设计中最凌乱也最具有挑战性的部分。</p><p>计算机系统中的 IO 设备按使用特性可分为以下类型。</p><ul><li>人机交互类外部设备</li><li>存储设备</li><li>网络通信设备</li></ul><h3 id="_5-1-2-i-o-控制方式" tabindex="-1">5.1.2 I/O 控制方式 <a class="header-anchor" href="#_5-1-2-i-o-控制方式" aria-label="Permalink to &quot;5.1.2 I/O 控制方式&quot;">​</a></h3><p>设备管理的主要任务之一是控制设备和内存或处理机之间的数据传送。</p><p>外围设备的输入/输出控制方式有 4 种。</p><ul><li>程序直接控制方式。CPU 对外设状态进行循环检查，CPU 利用率低</li><li>中断驱动方式。允许 IO 设备主动打断 CPU 的运行并请求服务。</li><li>DMA 方式。在 IO 和内存之间开辟直接的数据交换通路。</li><li>通道控制方式。IO 通道是专门负责输入输出的处理机。</li></ul><h3 id="_5-1-3-i-o-子系统的层次结构" tabindex="-1">5.1.3 I/O 子系统的层次结构 <a class="header-anchor" href="#_5-1-3-i-o-子系统的层次结构" aria-label="Permalink to &quot;5.1.3 I/O 子系统的层次结构&quot;">​</a></h3><p>为了使复杂的 IO 软件具有清晰的结构、良好的可移植性和适应性，在 IO 软件中普遍采用了层次式结构，将系统输入/输出组织成一系列的层次，每层都利用其下层提供的服务。</p><p>一个比较合理的层次划分如下</p><ul><li>用户层 IO 软件。实现与用户交互的接口</li><li>设备独立性软件。用于实现用户程序与设备驱动器的统一接口</li><li>设备驱动程序。与硬件直接相关，负责具体实现系统对设备发出的操作指令。</li><li>中断处理程序。用于保存被中断进程的 CPU 环境。</li><li>硬件设备。IO 设备通常包括一个机械部件和一个电子部件。电子部件称为设备控制器</li></ul><h2 id="_5-2-i-o-核心子系统" tabindex="-1">5.2 I/O 核心子系统 <a class="header-anchor" href="#_5-2-i-o-核心子系统" aria-label="Permalink to &quot;5.2 I/O 核心子系统&quot;">​</a></h2><h3 id="_5-2-1-i-o-子系统概述" tabindex="-1">5.2.1 I/O 子系统概述 <a class="header-anchor" href="#_5-2-1-i-o-子系统概述" aria-label="Permalink to &quot;5.2.1 I/O 子系统概述&quot;">​</a></h3><p>由于 IO 设备种类繁多，功能和传输速率差异巨大，因此需要多种方法来进行设备控制。这些方法共同组成了操作系统内核的 IO 子系统。</p><h3 id="_5-2-2-i-o-调度概念" tabindex="-1">5.2.2 I/O 调度概念 <a class="header-anchor" href="#_5-2-2-i-o-调度概念" aria-label="Permalink to &quot;5.2.2 I/O 调度概念&quot;">​</a></h3><p>IO 调度就是确定一个好的顺序来执行这些 IO 请求。</p><p>应用程序所发布的系统调用的顺序不一定总是最佳选择，所以需要 IO 调度来改善系统整体性能，使进程之间公平地共享设备访问，减少 IO 完成所需要的平均等待时间。</p><h3 id="_5-2-3-高速缓存与缓冲区" tabindex="-1">5.2.3 高速缓存与缓冲区 <a class="header-anchor" href="#_5-2-3-高速缓存与缓冲区" aria-label="Permalink to &quot;5.2.3 高速缓存与缓冲区&quot;">​</a></h3><ol><li>磁盘高速缓存（Disk Cache）。利用内存种的存储空间来暂存从磁盘中读出一系列盘块中的信息。</li><li>缓冲区。</li></ol><p>在设备管理子系统中，引入缓冲区的目的主要如下：</p><ul><li>缓和 CPU 与 IO 设备间速度不匹配的矛盾</li><li>减少对 CPU 的中断频率</li><li>解决基本数据单元大小不匹配的问题</li><li>提高 CPU 和 IO 设备间的并行性</li></ul><p>根据系统设置的缓冲器的个数，缓冲技术可以分为如下几种；</p><ul><li>单缓冲</li><li>双缓冲</li><li>循环缓冲</li><li>缓冲池</li></ul><ol start="3"><li>高速缓存 vs 缓冲区</li></ol><table><thead><tr><th>高速缓存</th><th>缓冲区</th></tr></thead><tbody><tr><td>存放低速设备上某些数据的拷贝</td><td>存放低速传给高速设备的数据</td></tr><tr><td>存放高速设备经常访问的数据</td><td>高度设备和低速设备的通信都要经过缓冲区</td></tr></tbody></table><h3 id="_5-2-4-设备分配与回收" tabindex="-1">5.2.4 设备分配与回收 <a class="header-anchor" href="#_5-2-4-设备分配与回收" aria-label="Permalink to &quot;5.2.4 设备分配与回收&quot;">​</a></h3><ol><li>设备分配概述</li><li>设备分配的数据结构</li><li>设备分配的策略</li><li>设备分配的安全性</li><li>逻辑设备名到物理设备名的映射</li></ol><h3 id="_5-2-5-spooling-技术" tabindex="-1">5.2.5 SPOOLing 技术 <a class="header-anchor" href="#_5-2-5-spooling-技术" aria-label="Permalink to &quot;5.2.5 SPOOLing 技术&quot;">​</a></h3><p>为了缓和 CPU 的高速性和 IO 设备低速性之间的矛盾，引入了脱机输入/输出技术。该技术利用专门的外围控制机，将低速 IO 设备上的数据传送到高速磁盘上。</p><ol><li>输入井和输出井</li><li>输入缓冲区和输出缓冲区</li><li>输入进程和输出进程</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>暂时告一段落</p></div>',35),r=[e];function h(s,n,d,c,_,p){return a(),l("div",null,r)}const I=i(o,[["render",h]]);export{O as __pageData,I as default};
